import React, {useEffect} from 'react';
import {fetchCartAction} from "../redux/productSlice.js";
import {useDispatch, useSelector} from "react-redux";

const Cart = () => {
	const products = useSelector(state => state.Products.cart?.products || []);
	const dispatch = useDispatch();

	useEffect(() => {
		dispatch(fetchCartAction());
	}, [dispatch]);

	return (
		<div>
			<h1 className={"text-5xl ms-4 my-4"}>Cart</h1>

			<div className={"grid grid-cols-1 lg:grid-cols-3 md:grid-cols-2 gap-4"}>
				{products.map((product, index) => (
					console.log("product in cart", product) ||
					<div
						key={product._id || index}
						className={"col-span-2 md:col-span-2 ms-5 b border  rounded shadow-lg w-full  bg-gray-100"}
					>
						<div className={"flex gap-4"}>
							<div>
								<img
									src={product.product.images}
									alt="Product Image"
									className={"max-w-45 h-45 object-cover rounded-lg"}
								/>
							</div>
							<div>
								<h1 className={"text-lg"}>{product.product.name}</h1>
								<h1 className={"text-lg"}>{product.product.description}</h1>
							</div>
							<div>
								<span className={"text-lg text-end font-bold"}>Price:{product.product.price}</span>
							</div>
						</div>

					</div>


				))}
				<div className={"col-span-1 gap-4 align-top  md:max-h-64 rounded-lg h-full"}>
							<div className={"max-h-64 h-full shadow-lg bg-green-300"}>
summery section 							</div>
						</div>
			</div>
		</div>
	);
};

export default Cart;

import React, {useEffect} from 'react';
import {fetchCartAction} from "../redux/productSlice.js";
import {useDispatch, useSelector} from "react-redux";

const Cart = () => {
	const products = useSelector(state => state.Products.cart?.products || []);
	const dispatch = useDispatch();

	useEffect(() => {
		dispatch(fetchCartAction());
	}, [dispatch]);

	return (
		<div>
			<h1 className={"text-5xl ms-4 my-4"}>Cart</h1>

			<div className={"grid grid-cols-1 lg:grid-cols-3 md:grid-cols-2 gap-4 mx-4"}>
				{/* Products Section */}
				<div className={"col-span-1 lg:col-span-2"}>
					<div className={"space-y-4"}>
						{products.map((product, index) => {
							console.log("product in cart", product);
							return (
								<div
									key={product._id || index}
									className={"border rounded shadow-lg bg-gray-100 p-4"}
								>
									<div className={"flex gap-4"}>
										<div>
											<img
												src={product.product.images}
												alt="Product Image"
												className={"max-w-45 h-45 object-cover rounded-lg"}
											/>
										</div>
										<div className={"flex-1"}>
											<h1 className={"text-lg font-semibold"}>{product.product.name}</h1>
											<p className={"text-sm text-gray-600"}>{product.product.description}</p>
											<span className={"text-lg font-bold text-green-600"}>₹{product.product.price}</span>
										</div>
									</div>
								</div>
							);
						})}
					</div>
				</div>

				{/* Summary Section */}
				<div className={"col-span-1 h-fit sticky top-4"}>
					<div className={"shadow-lg bg-green-300 rounded p-4"}>
						<h2 className={"text-xl font-bold mb-4"}>Order Summary</h2>
						<div className={"space-y-2"}>
							<div className={"flex justify-between"}>
								<span>Subtotal:</span>
								<span>₹0</span>
							</div>
							<div className={"flex justify-between"}>
								<span>Shipping:</span>
								<span>₹0</span>
							</div>
							<hr className={"my-2"} />
							<div className={"flex justify-between font-bold text-lg"}>
								<span>Total:</span>
								<span>₹0</span>
							</div>
							<button className={"w-full bg-blue-600 text-white py-2 rounded font-semibold mt-4 hover:bg-blue-700"}>
								Proceed to Checkout
							</button>
						</div>
					</div>
				</div>
			</div>
		</div>
	);
};

export default Cart;

const nodemailer= require('nodemailer');
const transporter = nodemailer.createTransport({
  host: "smtp.gmail.com",
  port: 587,
  secure: false, // use STARTTLS (upgrade connection to TLS after connecting)
  auth: {
    user: process.env.GMAIL_USER,
    pass: process.env.APP_PASSWORD,
  },
});


exports.sendOrderConfirmationEmail = async (recipientEmail, newOrder) => {
  try {
      console.log("order details ",newOrder);
    const info = await transporter.sendMail({

      from: '"Fasal Bazar" <team@example.com>',
      to: recipientEmail,
      subject: "Order Confirmation - Fasal Bazar",
      text: `Your order ${newOrder.orderId} has been placed successfully.`,
      html: `
        <div style="font-family: Arial, sans-serif; line-height: 1.6;">
          <h2 style="color: #2e6c80;">Order Confirmation</h2>
          <p>Thank you for shopping with <strong>Fasal Bazar</strong>!</p>

          <h3>Order Details</h3>
          <ul>
            <li><strong>Order ID:</strong> ${newOrder.orderId}</li>
            <li><strong>Status:</strong> ${newOrder.status}</li>
            <li><strong>Order Date:</strong> ${new Date(newOrder.orderDate).toLocaleString()}</li>
            <li><strong>Tracking ID:</strong> ${newOrder.trackingId}</li>
            <li><strong>Payment Method:</strong> ${newOrder.paymentMethod}</li>
          </ul>

          <h3>Product Details</h3>
          <ul>
            <li><strong>Product ID:</strong> ${newOrder.product}</li>
            <li><strong>Quantity:</strong> ${newOrder.quantity}</li>
            <li><strong>Total Amount:</strong> ₹${newOrder.amount}</li>
          </ul>

          <h3>Shipping Address</h3>
          <p>
            ${newOrder.buyer.address}<br/>
            Pincode: ${newOrder.buyer.pincode}
          </p>

          <p style="margin-top:20px;">We’ll notify you once your order is shipped.</p>
          <p>— Team Fasal Bazar</p>
        </div>
      `,
    });

    console.log("Message sent: %s", info.messageId);
  } catch (err) {
    console.error("Error while sending mail:", err);
  }
};

